import { useState, useEffect, useRef, useCallback } from "react";

const API = "http://localhost:8000";

// ─── Design tokens ─────────────────────────────────────────────────────────
const C = {
  bg:       "#040407",
  surface:  "#08080f",
  border:   "#12121e",
  red:      "#ff3355",
  blue:     "#3d8bff",
  green:    "#00e676",
  yellow:   "#ffd740",
  orange:   "#ff9100",
  dim:      "#3a3a55",
  muted:    "#666680",
  text:     "#c8c8e0",
};

const SEV = { CRITICAL: C.red, HIGH: C.orange, MEDIUM: C.yellow, LOW: C.green };

// ─── Tiny helpers ──────────────────────────────────────────────────────────
const Badge = ({ label, color }) => (
  <span style={{ background: color + "22", color, border: `1px solid ${color}44`, borderRadius: 4, padding: "2px 8px", fontSize: 10, letterSpacing: 1, fontWeight: 700 }}>
    {label}
  </span>
);

const Mono = ({ children, color = C.muted, size = 11 }) => (
  <span style={{ fontFamily: "monospace", fontSize: size, color }}>{children}</span>
);

const Label = ({ children }) => (
  <div style={{ fontSize: 9, letterSpacing: 2, color: C.dim, textTransform: "uppercase", marginBottom: 8 }}>{children}</div>
);

const Card = ({ children, accent, style = {} }) => (
  <div style={{
    background: C.surface,
    border: `1px solid ${accent ? accent + "33" : C.border}`,
    borderRadius: 8,
    padding: 16,
    ...style,
  }}>
    {children}
  </div>
);

// ─── Model Unavailable screen ─────────────────────────────────────────────
function ModelUnavailable({ error }) {
  return (
    <div style={{ display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", minHeight: "60vh", gap: 16, padding: 32 }}>
      <div style={{ fontSize: 48 }}>⚠</div>
      <div style={{ fontSize: 22, fontWeight: 800, color: C.red, fontFamily: "monospace", letterSpacing: 2 }}>MODEL UNAVAILABLE</div>
      <div style={{ color: C.muted, fontSize: 13, maxWidth: 480, textAlign: "center", lineHeight: 1.8 }}>
        Gemma 4 via Ollama is not reachable. GemmaShield does not simulate or mock AI responses.
      </div>
      <Card accent={C.red} style={{ maxWidth: 520, width: "100%" }}>
        <Label>Error Details</Label>
        <Mono color={C.red} size={12}>{error?.detail || JSON.stringify(error)}</Mono>
      </Card>
      <Card style={{ maxWidth: 520, width: "100%" }}>
        <Label>Resolution Steps</Label>
        <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
          {[
            "1. Install Ollama → https://ollama.com",
            "2. Run: ollama pull gemma4",
            "3. Ensure Ollama service is running",
            "4. Start backend: uvicorn main:app --reload",
          ].map(s => <Mono key={s} color={C.text} size={12}>{s}</Mono>)}
        </div>
      </Card>
    </div>
  );
}

// ─── Debug Panel ──────────────────────────────────────────────────────────
function DebugPanel({ data }) {
  const [open, setOpen] = useState(false);
  if (!data) return null;

  const agents = ["attack", "target", "defense", "verdict"].map(k => ({
    key: k,
    d: data[k],
  })).filter(a => a.d);

  return (
    <div style={{ marginTop: 16 }}>
      <button
        onClick={() => setOpen(o => !o)}
        style={{ background: "none", border: `1px solid ${C.border}`, color: C.muted, padding: "6px 14px", borderRadius: 6, cursor: "pointer", fontSize: 11, letterSpacing: 1 }}
      >
        {open ? "▼" : "▶"} DEBUG PANEL — Model Trace
      </button>

      {open && (
        <div style={{ marginTop: 12, display: "flex", flexDirection: "column", gap: 10 }}>
          {agents.map(({ key, d }) => (
            <Card key={key} style={{ borderLeft: `3px solid ${C.blue}` }}>
              <div style={{ display: "flex", gap: 16, marginBottom: 10, flexWrap: "wrap" }}>
                <Badge label={d.agent?.toUpperCase() || key.toUpperCase()} color={C.blue} />
                <Mono>model: <span style={{ color: C.green }}>{d.model}</span></Mono>
                <Mono>source: <span style={{ color: C.yellow }}>{d.source}</span></Mono>
                <Mono>latency: <span style={{ color: C.orange }}>{d.latency_ms}ms</span></Mono>
              </div>
              <Label>Raw LLM Output</Label>
              <pre style={{ margin: 0, fontSize: 10, color: C.muted, background: C.bg, padding: 12, borderRadius: 4, overflow: "auto", maxHeight: 160, whiteSpace: "pre-wrap", wordBreak: "break-word" }}>
                {d.raw_output}
              </pre>
            </Card>
          ))}

          <Card>
            <Label>Total Pipeline Latency</Label>
            <Mono color={C.orange} size={20}>{data.total_latency_ms?.toLocaleString()}ms</Mono>
            <Mono color={C.muted}> ({(data.total_latency_ms / 1000).toFixed(1)}s)</Mono>
          </Card>
        </div>
      )}
    </div>
  );
}

// ─── Phase Log entry ──────────────────────────────────────────────────────
function PhaseEntry({ event }) {
  const { phase } = event;
  const phaseColors = {
    init: C.muted, attacker_start: C.red, attacker_done: C.red,
    target_start: C.muted, target_done: C.muted,
    defender_start: C.blue, defender_done: C.blue,
    judge_start: C.yellow, judge_done: C.yellow,
    complete: C.green, error: C.red,
  };
  const color = phaseColors[phase] || C.muted;
  const isDone = phase.endsWith("_done");
  const isError = phase === "error";

  return (
    <div style={{ display: "flex", gap: 10, padding: "7px 0", borderBottom: `1px solid ${C.bg}` }}>
      <Mono color={color} size={13}>{isError ? "✗" : isDone ? "✓" : "◌"}</Mono>
      <div style={{ flex: 1 }}>
        <span style={{ color, fontFamily: "monospace", fontSize: 11, letterSpacing: 1 }}>[{phase.toUpperCase()}]</span>
        {event.message && <span style={{ color: C.muted, fontFamily: "monospace", fontSize: 11, marginLeft: 8 }}>{event.message}</span>}
        {isDone && event.agent && (
          <span style={{ marginLeft: 8 }}>
            <Badge label={`${event.model} · ${event.source} · ${event.latency_ms}ms`} color={color} />
          </span>
        )}
        {isError && (
          <div style={{ marginTop: 6, color: C.red, fontFamily: "monospace", fontSize: 11 }}>
            {event.detail}
          </div>
        )}
      </div>
    </div>
  );
}

// ─── Verdict Card ─────────────────────────────────────────────────────────
function VerdictCard({ battle }) {
  if (!battle?.verdict?.output) return null;
  const v = battle.verdict.output;
  const a = battle.attack?.output || {};
  const d = battle.defense?.output || {};
  const sev = v.severity || a.severity;

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
      <Card accent={SEV[sev]}>
        <Label>Final CVSS-like Score</Label>
        <div style={{ fontSize: 52, fontWeight: 900, fontFamily: "monospace", color: SEV[sev], lineHeight: 1 }}>
          {v.cvss_like_score}
          <span style={{ fontSize: 18, color: C.muted }}>/10</span>
        </div>
        <div style={{ marginTop: 8 }}>
          <Badge label={sev} color={SEV[sev]} />
        </div>
      </Card>

      <Card>
        <Label>Vulnerability</Label>
        <Mono color={C.text} size={11}>{v.vulnerability_label}</Mono>
      </Card>

      <Card accent={d.blocked ? C.green : C.red}>
        <Label>Defense Status</Label>
        <div style={{ fontSize: 18, fontWeight: 800, color: d.blocked ? C.green : C.red, fontFamily: "monospace" }}>
          {d.blocked ? "✓ BLOCKED" : "✗ BREACHED"}
        </div>
        <div style={{ marginTop: 4 }}><Mono>confidence: {d.confidence}</Mono></div>
      </Card>

      <Card>
        <Label>Patch Priority</Label>
        <Mono color={C.orange} size={13}>{v.patch_priority}</Mono>
      </Card>

      <Card>
        <Label>Judge Reasoning</Label>
        <Mono color={C.muted} size={11}>{v.judge_reasoning}</Mono>
      </Card>

      <Card>
        <Label>Recommendation</Label>
        <div style={{ color: C.text, fontSize: 11, lineHeight: 1.7 }}>{v.recommendation}</div>
      </Card>
    </div>
  );
}

// ─── Battle Console ───────────────────────────────────────────────────────
function BattleConsole({ onComplete }) {
  const [logs, setLogs] = useState([]);
  const [running, setRunning] = useState(false);
  const [battle, setBattle] = useState(null);
  const [modelError, setModelError] = useState(null);
  const [target, setTarget] = useState("Healthcare AI Assistant");
  const [attackType, setAttackType] = useState("any");
  const logsRef = useRef(null);

  useEffect(() => {
    logsRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [logs]);

  const runBattle = async () => {
    setLogs([]);
    setBattle(null);
    setModelError(null);
    setRunning(true);

    const params = new URLSearchParams({ target_system: target, attack_type: attackType });

    try {
      const res = await fetch(`${API}/battle/stream?${params}`, { method: "POST" });

      if (!res.ok) {
        const err = await res.json();
        setModelError(err.detail);
        setRunning(false);
        return;
      }

      const reader = res.body.getReader();
      const decoder = new TextDecoder();
      let assembled = {};

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;
        const lines = decoder.decode(value).split("\n").filter(l => l.startsWith("data: "));
        for (const line of lines) {
          try {
            const event = JSON.parse(line.slice(6));
            setLogs(prev => [...prev, event]);

            if (event.phase === "error") {
              setModelError(event);
              setRunning(false);
              return;
            }
            if (event.phase === "attacker_done") assembled.attack = event;
            if (event.phase === "target_done")   assembled.target = event;
            if (event.phase === "defender_done") assembled.defense = event;
            if (event.phase === "judge_done")    assembled.verdict = event;
            if (event.phase === "complete") {
              assembled.battle_id = event.battle_id;
              assembled.total_latency_ms = event.total_latency_ms;
              setBattle(assembled);
              onComplete?.();
            }
          } catch {}
        }
      }
    } catch {
      setModelError({ error: "MODEL_UNAVAILABLE", detail: "Cannot reach backend. Start: uvicorn main:app --reload" });
    }
    setRunning(false);
  };

  return (
    <div style={{ display: "flex", gap: 16, height: "calc(100vh - 180px)", minHeight: 560 }}>
      {/* Left: Console */}
      <div style={{ flex: 1.4, display: "flex", flexDirection: "column", minWidth: 0 }}>
        {/* Controls */}
        <div style={{ display: "flex", gap: 8, marginBottom: 12, flexWrap: "wrap" }}>
          <input value={target} onChange={e => setTarget(e.target.value)}
            placeholder="Target system..."
            style={{ flex: 1, background: C.surface, border: `1px solid ${C.border}`, color: C.text, padding: "8px 12px", borderRadius: 6, fontFamily: "monospace", fontSize: 12, minWidth: 140 }}
          />
          <select value={attackType} onChange={e => setAttackType(e.target.value)}
            style={{ background: C.surface, border: `1px solid ${C.border}`, color: C.muted, padding: "8px 10px", borderRadius: 6, fontSize: 12 }}>
            <option value="any">Auto Select</option>
            <option value="prompt_injection">Prompt Injection</option>
            <option value="jailbreak">Jailbreak</option>
            <option value="role_override">Role Override</option>
            <option value="data_extraction">Data Extraction</option>
            <option value="deception">Deception</option>
          </select>
          <button onClick={runBattle} disabled={running}
            style={{ background: running ? C.surface : C.red, color: running ? C.dim : "#fff", border: "none", padding: "8px 20px", borderRadius: 6, cursor: running ? "not-allowed" : "pointer", fontWeight: 800, fontSize: 12, letterSpacing: 1, fontFamily: "monospace", transition: "background 0.2s" }}>
            {running ? "RUNNING..." : "▶ BATTLE"}
          </button>
        </div>

        {/* Log stream */}
        <div style={{ flex: 1, background: C.bg, border: `1px solid ${C.border}`, borderRadius: 8, padding: 16, overflow: "auto" }}>
          <div style={{ color: C.dim, fontSize: 10, letterSpacing: 2, marginBottom: 12, fontFamily: "monospace" }}>
            GEMMASHIELD v2 ── GEMMA 4 via OLLAMA ── LLM-ONLY MODE ────────────────────────────────
          </div>

          {modelError && <ModelUnavailable error={modelError} />}

          {logs.length === 0 && !modelError && (
            <div style={{ color: C.dim, fontSize: 12, textAlign: "center", marginTop: 60, fontFamily: "monospace" }}>
              Awaiting command.<br />All agents use Gemma 4 exclusively.
            </div>
          )}

          {logs.map((e, i) => <PhaseEntry key={i} event={e} />)}
          <div ref={logsRef} />
        </div>

        {/* Debug panel under console */}
        {battle && <DebugPanel data={battle} />}
      </div>

      {/* Right: Verdict */}
      <div style={{ width: 270, overflow: "auto" }}>
        {battle ? (
          <VerdictCard battle={battle} />
        ) : (
          <Card style={{ height: "100%", display: "flex", alignItems: "center", justifyContent: "center" }}>
            <div style={{ color: C.dim, fontSize: 11, textAlign: "center", fontFamily: "monospace" }}>
              Verdict panel<br />awaiting<br />battle results
            </div>
          </Card>
        )}
      </div>
    </div>
  );
}

// ─── Dashboard ────────────────────────────────────────────────────────────
function Dashboard({ refresh }) {
  const [stats, setStats] = useState(null);
  const [battles, setBattles] = useState([]);
  const [error, setError] = useState(null);

  useEffect(() => {
    Promise.all([
      fetch(`${API}/analytics`).then(r => r.json()),
      fetch(`${API}/logs?limit=25`).then(r => r.json()),
    ]).then(([s, b]) => {
      setStats(s);
      setBattles(b.battles || []);
    }).catch(() => setError("Cannot reach backend."));
  }, [refresh]);

  if (error) return <div style={{ color: C.red, fontFamily: "monospace", padding: 32 }}>{error}</div>;

  return (
    <div>
      {stats && (
        <div style={{ display: "flex", gap: 12, marginBottom: 24, flexWrap: "wrap" }}>
          {[
            { label: "Total Battles", value: stats.total_battles, color: C.blue },
            { label: "Block Rate", value: `${stats.block_rate}%`, color: C.green },
            { label: "Avg Risk", value: stats.avg_risk_score, color: C.orange },
            { label: "Avg CVSS", value: stats.avg_cvss_score, color: C.red },
            { label: "Avg Latency", value: `${(stats.avg_latency_ms / 1000).toFixed(1)}s`, color: C.yellow },
          ].map(s => (
            <Card key={s.label} accent={s.color} style={{ flex: 1, minWidth: 110 }}>
              <div style={{ fontSize: 26, fontWeight: 900, color: s.color, fontFamily: "monospace" }}>{s.value}</div>
              <div style={{ fontSize: 10, color: C.muted, marginTop: 4, letterSpacing: 1, textTransform: "uppercase" }}>{s.label}</div>
            </Card>
          ))}
        </div>
      )}

      {stats?.attack_distribution?.length > 0 && (
        <div style={{ marginBottom: 20 }}>
          <Label>Attack Distribution</Label>
          <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
            {stats.attack_distribution.map(a => (
              <div key={a.type} style={{ background: C.surface, border: `1px solid ${C.border}`, borderRadius: 6, padding: "6px 14px", fontSize: 12 }}>
                <Mono color={C.text}>{a.type?.replace(/_/g, " ")}</Mono>
                <Mono color={C.red}> ×{a.count}</Mono>
              </div>
            ))}
          </div>
        </div>
      )}

      <Label>Battle History</Label>
      <div style={{ background: C.surface, border: `1px solid ${C.border}`, borderRadius: 8, overflow: "auto" }}>
        {battles.length === 0 ? (
          <div style={{ padding: 32, color: C.dim, textAlign: "center", fontFamily: "monospace", fontSize: 12 }}>
            No battles yet. Run a battle first.
          </div>
        ) : (
          <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 11, fontFamily: "monospace" }}>
            <thead>
              <tr style={{ borderBottom: `1px solid ${C.border}` }}>
                {["ID", "TARGET", "ATTACK", "SEV", "CVSS", "STATUS", "LATENCY"].map(h => (
                  <th key={h} style={{ padding: "10px 14px", textAlign: "left", color: C.dim, letterSpacing: 1, fontWeight: 400 }}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {battles.map((b, i) => {
                const atk = b.attack?.output || {};
                const def = b.defense?.output || {};
                const jdg = b.verdict?.output || {};
                return (
                  <tr key={i} style={{ borderBottom: `1px solid ${C.bg}` }}>
                    <td style={{ padding: "9px 14px", color: C.dim }}>{b.battle_id}</td>
                    <td style={{ padding: "9px 14px", color: C.muted }}>{b.target_system?.slice(0, 18)}</td>
                    <td style={{ padding: "9px 14px", color: C.text }}>{atk.attack_type?.replace(/_/g, " ")}</td>
                    <td style={{ padding: "9px 14px" }}><Badge label={atk.severity || "?"} color={SEV[atk.severity] || C.muted} /></td>
                    <td style={{ padding: "9px 14px", color: C.orange }}>{jdg.cvss_like_score ?? "—"}</td>
                    <td style={{ padding: "9px 14px", color: def.blocked ? C.green : C.red }}>{def.blocked ? "BLOCKED" : "BREACHED"}</td>
                    <td style={{ padding: "9px 14px", color: C.muted }}>{b.total_latency_ms ? `${(b.total_latency_ms / 1000).toFixed(1)}s` : "—"}</td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
}

// ─── Landing ──────────────────────────────────────────────────────────────
function Landing() {
  return (
    <div style={{ padding: "56px 0", maxWidth: 680 }}>
