// ─── Root ─────────────────────────────────────────────────────────────────
export default function App() {
  const [page, setPage] = useState("home");
  const [refresh, setRefresh] = useState(0);

  const tabs = [
    { id: "home",      label: "◈ HOME" },
    { id: "console",   label: "▶ BATTLE CONSOLE" },
    { id: "dashboard", label: "◉ DASHBOARD" },
  ];

  return (
    <div style={{ minHeight: "100vh", background: C.bg, color: C.text }}>
      <style>{`
        * { box-sizing: border-box; margin: 0; padding: 0; }
        body { background: ${C.bg}; }
        ::-webkit-scrollbar { width: 4px; height: 4px; }
        ::-webkit-scrollbar-track { background: ${C.bg}; }
        ::-webkit-scrollbar-thumb { background: ${C.border}; border-radius: 2px; }
        select option { background: ${C.surface}; }
        @keyframes pulse { 0%,100%{opacity:1} 50%{opacity:0.4} }
        .pulse { animation: pulse 1.5s infinite; }
      `}</style>

      {/* Nav */}
      <div style={{ borderBottom: `1px solid ${C.border}`, padding: "0 32px", display: "flex", alignItems: "center", gap: 0 }}>
        <div style={{ padding: "14px 0", fontSize: 15, fontWeight: 900, fontFamily: "monospace", marginRight: 32, letterSpacing: -0.5 }}>
          GEMMA<span style={{ color: C.red }}>SHIELD</span>
          <span style={{ fontSize: 9, color: C.dim, letterSpacing: 2, marginLeft: 10 }}>v2.0</span>
        </div>
        {tabs.map(t => (
          <button key={t.id} onClick={() => setPage(t.id)}
            style={{
              background: "none", border: "none",
              borderBottom: page === t.id ? `2px solid ${C.red}` : "2px solid transparent",
              color: page === t.id ? C.text : C.muted,
              padding: "14px 18px", cursor: "pointer",
              fontSize: 10, letterSpacing: 1.5, fontFamily: "monospace",
              transition: "color 0.15s",
            }}>
            {t.label}
          </button>
        ))}
        <div style={{ marginLeft: "auto", display: "flex", gap: 16, alignItems: "center" }}>
          <div style={{ fontSize: 9, color: C.dim, letterSpacing: 1, fontFamily: "monospace" }}>
            MODEL: GEMMA 4 · SOURCE: OLLAMA · NO FALLBACKS
          </div>
        </div>
      </div>

      {/* Page */}
      <div style={{ padding: "28px 32px" }}>
        {page === "home"      && <Landing />}
        {page === "console"   && <BattleConsole onComplete={() => setRefresh(r => r + 1)} />}
        {page === "dashboard" && <Dashboard refresh={refresh} />}
      </div>
    </div>
  );
}
